<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Ubuntu-Inspired Desktop</title>
  <style>
    * { box-sizing: border-box; }
    body, #desktop {
      margin: 0;
      padding: 0;
      width: 100vw;
      height: 100vh;
      overflow: hidden;
      font-family: sans-serif;
      background-color: #2c001e;
      color: white;
    }
    #taskbar {
      position: absolute;
      bottom: 0;
      left: 0;
      width: 100%;
      height: 48px;
      background-color: #3a002d;
      display: flex;
      align-items: center;
      padding: 0 16px;
    }
    .taskbar-btn {
      margin-right: 16px;
      cursor: pointer;
      color: white;
      font-weight: bold;
      border: none;
      background: none;
    }
    .window {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 480px;
      min-height: 320px;
      max-height: calc(100vh - 64px);
      background-color: #1c1c1c;
      border-radius: 8px;
      box-shadow: 0 0 15px rgba(0,0,0,0.7);
      display: none;
      flex-direction: column;
    }
    .window-header {
      height: 32px;
      background-color: #4a003d;
      padding: 8px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-radius: 8px 8px 0 0;
    }
    .win-close {
      cursor: pointer;
      color: white;
      font-weight: bold;
    }
    #files-window, #notepad-window {
      display: flex;
      flex-direction: column;
    }
    #files-path {
      padding: 12px;
      background-color: #3a002d;
      border-radius: 4px;
      margin-bottom: 8px;
    }
    .fs-item {
      cursor: pointer;
      padding: 6px 12px;
      margin: 2px 0;
      transition: background 0.2s;
    }
    .fs-item:hover { background-color: #4a003d; }
    .folder { color: #7ec4cf; font-weight: bold; }
    .file { color: #f5c2e7; }
    #files-up {
      margin-top: 8px;
      cursor: pointer;
      padding: 6px 12px;
      background-color: #3a002d;
      border-radius: 4px;
    }
    .tab-strip {
      display: flex;
      height: 32px;
      overflow-x: auto;
      border-bottom: 1px solid #555;
    }
    .tab {
      cursor: pointer;
      padding: 6px 12px;
      background-color: #4a003d;
      margin-right: 2px;
      white-space: nowrap;
    }
    .tab.active { background-color: #7ec4cf; color: black; }
    #new-tab {
      cursor: pointer;
      padding: 6px 12px;
      background-color: #4a003d;
      margin-left: 8px;
    }
    #editor {
      flex-grow: 1;
      resize: none;
      outline: none;
      font-family: monospace;
      padding: 12px;
      border: none;
      background-color: #1c1c1c;
      color: white;
    }
  </style>
</head>
<body>
  <div id="desktop">
    <div id="taskbar">
      <button class="taskbar-btn" id="open-files">Files</button>
      <button class="taskbar-btn" id="open-notepad">Notepad</button>
    </div>

    <!-- Files Window -->
    <div class="window" id="files-window">
      <div class="window-header">
        <span>Files</span>
        <span class="win-close">&times;</span>
      </div>
      <div id="files-path">/</div>
      <div id="file-list"></div>
      <div id="files-up">&#9650; Up</div>
    </div>

    <!-- Notepad Window -->
    <div class="window" id="notepad-window">
      <div class="window-header">
        <span>Notepad</span>
        <span class="win-close">&times;</span>
      </div>
      <div class="tab-strip" id="tabs">
        <button class="tab active">Untitled 1</button>
        <button class="new-tab" id="new-tab">&#43; New Tab</button>
      </div>
      <textarea id="editor"></textarea>
    </div>
  </div>

  <script>
    // File system structure
    const fileSystem = {
      "/": ["bin", "etc", "home", "usr", "var"],
      "/bin": [],
      "/etc": [],
      "/home": ["user"],
      "/home/user": ["Documents", "Downloads", "Pictures", "notes.txt"],
      "/home/user/Documents": [],
      "/home/user/Downloads": [],
      "/home/user/Pictures": [],
      "/usr": [],
      "/var": []
    };

    // Files Window Logic
    const filesWindow = document.getElementById('files-window');
    const fileUpBtn = document.getElementById('files-up');
    const filePathDisplay = document.getElementById('files-path');
    const fileListContainer = document.getElementById('file-list');

    let currentPath = "/";

    function renderFiles(path) {
      filePathDisplay.textContent = path;
      const items = fileSystem[path] || [];

      fileListContainer.innerHTML = '';
      items.forEach(item => {
        const itemEl = document.createElement('div');
        itemEl.className = 'fs-item';
        itemEl.textContent = item;

        // Determine if folder
        const fullPath = path + (path === "/" ? "" : "/") + item;
        if (fileSystem[fullPath] !== undefined) {
          itemEl.classList.add('folder');
        } else {
          itemEl.classList.add('file');
        }

        itemEl.addEventListener('dblclick', () => {
          const fullPath = path + (path === "/" ? "" : "/") + item;
          if (fileSystem[fullPath] !== undefined) {
            currentPath = fullPath;
            renderFiles(fullPath);
          }
        });

        fileListContainer.appendChild(itemEl);
      });

      fileUpBtn.style.display = path === "/" ? "none" : "inline-block";
    }

    fileUpBtn.addEventListener('click', () => {
      if (currentPath !== "/") {
        const parts = currentPath.split('/');
        parts.pop();
        currentPath = parts.join('/') || "/";
        renderFiles(currentPath);
      }
    });

    // Notepad Window Logic
    const notepadWindow = document.getElementById('notepad-window');
    const tabsContainer = document.getElementById('tabs');
    const editorArea = document.getElementById('editor');
    const newTabBtn = document.getElementById('new-tab');

    let tabCounter = 1;

    function loadTabs() {
      try {
        const savedData = localStorage.getItem('notepad-tabs');
        if (savedData) {
          const tabs = JSON.parse(savedData);

          // Clear existing
          tabsContainer.innerHTML = '';
          editorArea.value = '';

          // Restore tabs
          tabs.forEach((tab, index) => {
            createTab(tab.title, tab.content, index === 0);
          });
        } else {
          createTab("Untitled 1", "", true);
        }
      } catch (e) {
        console.error('Error loading notepad:', e);
        createTab("Untitled 1", "", true);
      }
    }

    function saveTabs() {
      const tabs = [];

      // Get all tab elements
      document.querySelectorAll('.tab').forEach((tabEl, index) => {
        const title = tabEl.textContent;
        let content = "";

        if (index === currentTabIdx) {
          content = editorArea.value;
        }

        tabs.push({ title, content });
      });

      localStorage.setItem('notepad-tabs', JSON.stringify(tabs));
    }

    function createTab(title, content, isActive) {
      const tabEl = document.createElement('button');
      tabEl.className = 'tab';
      if (isActive) tabEl.classList.add('active');
      tabEl.textContent = title;
      tabsContainer.insertBefore(tabEl, newTabBtn);

      // Add event listener
      tabEl.addEventListener('click', () => {
        document.querySelector('.tab.active')?.classList.remove('active');
        tabEl.classList.add('active');

        const idx = Array.from(tabsContainer.children).indexOf(tabEl);
        editorArea.value = tabsData[idx].content;
        currentTabIdx = idx;
      });

      // Store in array
      if (!tabsData) {
        tabsData = [];
      }
      tabsData.push({ title, content });
    }

    let tabsData = [];
    let currentTabIdx = 0;

    newTabBtn.addEventListener('click', () => {
      const tabTitle = "Untitled " + (tabCounter++);
      createTab(tabTitle, "", true);
      saveTabs();
    });

    editorArea.addEventListener('input', saveTabs);

    // Window Management
    function showWindow(windowEl) {
      document.querySelectorAll('.window').forEach(w => w.style.display = 'none');
      windowEl.style.display = 'flex';
    }

    document.getElementById('open-files').addEventListener('click', () => {
      renderFiles(currentPath);
      showWindow(filesWindow);
    });

    document.getElementById('open-notepad').addEventListener('click', () => {
      loadTabs();
      showWindow(notepadWindow);
    });

    // Close buttons
    document.querySelectorAll('.win-close').forEach(btn => {
      btn.addEventListener('click', () => {
        const windowEl = btn.closest('.window');
        windowEl.style.display = 'none';
      });
    });

    // Initial render
    loadTabs();
  </script>
</body>
</html>
